def recall_at_k(index, eval_set, k=3):
    hits = 0
    for query, expected in eval_set:
        results = index.search(query, top_k=k)
        retrieved = [doc for doc, _ in results]
        if expected in retrieved:
            hits += 1
    return hits / len(eval_set)

eval_set = [
    ("How do I get a refund?", "Refunds take 3-5 days."),
    ("Set up two-factor auth", "Enable 2FA in Settings."),
]
score = recall_at_k(index, eval_set, k=2)
print(f"Recall@2: {score:.2f}")
